#include "HttpReferenceProvider.h"
namespace referencelab { bool HttpReferenceProvider::isValidAudioUrl(const juce::String&s){auto u=juce::URL(s.trim());auto scheme=u.getScheme().toLowerCase();if(scheme!="http"&&scheme!="https")return false;if(u.getDomain().isEmpty()||u.getDomain().containsAnyOf(" \\"))return false;auto p=u.getSubPath().upToFirstOccurrenceOf("?",false,false);return p.endsWithIgnoreCase(".wav")||p.endsWithIgnoreCase(".aif")||p.endsWithIgnoreCase(".aiff")||p.endsWithIgnoreCase(".flac")||p.endsWithIgnoreCase(".mp3");}bool HttpReferenceProvider::supportsUrl(const juce::URL&u)const{return isValidAudioUrl(u.toString(false));}std::optional<ReferenceMetadata>HttpReferenceProvider::inspectUrl(const juce::URL&u,juce::String&e){if(!supportsUrl(u)){e="URL audio non valido: richiesti HTTP/HTTPS e WAV, AIFF, FLAC o MP3";return{};}ReferenceMetadata m;m.provider=id();m.source=u.toString(false);m.title=u.getFileName().upToLastOccurrenceOf(".",false,false);if(m.title.isEmpty())m.title=u.getDomain();return m;} }
